import pytest
import requests

def test_create_procedure_empty_string_encounter_reference_is_rejected(
    base_url, auth_headers
):
    payload = {
        "resourceType": "Procedure",
        "status": "completed",
        "subject": {"reference": "Patient/test-patient-1"},
        "encounter": {"reference": ""},
        "code": {"text": "Blood pressure measurement"}
    }
    resp = requests.post(
        f"{base_url}/Procedure",
        json=payload,
        headers=auth_headers
    )
    assert resp.status_code in (400, 422), (
        f"Expected 400 or 422 for empty encounter ref, got {resp.status_code}: {resp.text}"
    )
    body = resp.json()
    assert body.get("resourceType") == "OperationOutcome"
    assert "id" not in body, "Procedure must not be persisted with empty encounter reference"
